import pandas as pd
from collections import Counter

def task_func(df):
    # Ensure the DataFrame has no duplicate rows
    df = df.drop_duplicates()

    # Create a new column 'combination' containing combinations of items in each row
    def get_combinations(row):
        return tuple(sorted(row))
    df['combination'] = df.apply(get_combinations, axis=1)

    # Calculate the frequency of each combination
    combination_freq = Counter(df['combination'])

    return tuple(combination_freq)
